1	import { useEffect, useState, useRef } from 'react'
2	import { createPortal } from 'react-dom'
3	import './CardModal.css'
4	
5	export default function CardModal({ card, onClose, onUpdate, onDelete }) {
6	  // Edit state
7	  const [isEditingTitle, setIsEditingTitle] = useState(false)
8	  const [editTitle, setEditTitle]           = useState(card.title)
9	  const [isEditingAssignee, setIsEditingAssignee] = useState(false)
10	  const [editAssignee, setEditAssignee]     = useState(card.assignee ?? '')
11	  const [isSaving, setIsSaving]             = useState(false)
12	  const [saveError, setSaveError]           = useState(null)
13	
14	  // Delete state
15	  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)
16	  const [isDeleting, setIsDeleting]               = useState(false)
17	
18	  // Focus refs
19	  const titleInputRef    = useRef(null)
20	  const assigneeInputRef = useRef(null)
21	
22	  // Focus effects
23	  useEffect(() => {
24	    if (isEditingTitle && titleInputRef.current) titleInputRef.current.focus()
25	  }, [isEditingTitle])
26	
27	  useEffect(() => {
28	    if (isEditingAssignee && assigneeInputRef.current) assigneeInputRef.current.focus()
29	  }, [isEditingAssignee])
30	
31	  // Escape key handler — replaces the original handler
32	  useEffect(() => {
33	    function onKey(e) {
34	      if (e.key !== 'Escape') return
35	      if (isEditingTitle) {
36	        setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
37	      } else if (isEditingAssignee) {
38	        setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
39	      } else {
40	        onClose()
41	      }
42	    }
43	    document.addEventListener('keydown', onKey)
44	    return () => document.removeEventListener('keydown', onKey)
45	  }, [onClose, isEditingTitle, isEditingAssignee, card.title, card.assignee])
46	
47	  // Save handlers
48	  async function handleSaveTitle() {
49	    if (editTitle.trim() === '') {
50	      setSaveError('Title is required')
51	      return
52	    }
53	    setIsSaving(true); setSaveError(null)
54	    try {
55	      await onUpdate(card.id, { title: editTitle })
56	      setIsEditingTitle(false)
57	    } catch (err) {
58	      setSaveError(err.message)
59	    } finally {
60	      setIsSaving(false)
61	    }
62	  }
63	
64	  async function handleSaveAssignee() {
65	    setIsSaving(true); setSaveError(null)
66	    try {
67	      await onUpdate(card.id, { assignee: editAssignee === '' ? null : editAssignee })
68	      setIsEditingAssignee(false)
69	    } catch (err) {
70	      setSaveError(err.message)
71	    } finally {
72	      setIsSaving(false)
73	    }
74	  }
75	
76	  async function handleConfirmDelete() {
77	    setIsDeleting(true); setSaveError(null)
78	    try {
79	      await onDelete(card.id)
80	      onClose()
81	    } catch (err) {
82	      setSaveError(err.message)
83	      setShowDeleteConfirm(false)
84	    } finally {
85	      setIsDeleting(false)
86	    }
87	  }
88	
89	  return createPortal(
90	    <div className="modal-overlay" onClick={onClose}>
91	      <div
92	        className="modal-content"
93	        role="dialog"
94	        aria-modal="true"
95	        aria-label={card.title}
96	        onClick={e => e.stopPropagation()}
97	      >
98	        {/* 1. Close button */}
99	        <button className="modal-close" onClick={onClose} aria-label="Close">
100	          ✕
101	        </button>
102	
103	        {/* 2. Title field (editable) */}
104	        {isEditingTitle ? (
105	          <div className="modal-field-edit">
106	            <input
107	              ref={titleInputRef}
108	              aria-label="Title"
109	              value={editTitle}
110	              onChange={e => setEditTitle(e.target.value)}
111	              onKeyDown={e => { if (e.key === 'Enter') handleSaveTitle() }}
112	            />
113	            <button aria-label="Save" onClick={handleSaveTitle} disabled={isSaving}>
114	              {isSaving ? 'Saving…' : 'Save'}
115	            </button>
116	            <button
117	              aria-label="Cancel"
118	              disabled={isSaving}
119	              onClick={() => { setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null) }}
120	            >
121	              Cancel
122	            </button>
123	          </div>
124	        ) : (
125	          <div className="modal-field-view">
126	            <h2 className="modal-title">{card.title}</h2>
127	            <button
128	              aria-label="Edit title"
129	              onClick={() => {
130	                setIsEditingTitle(true); setEditTitle(card.title)
131	                // Mutual exclusivity: close assignee edit if open
132	                setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
133	              }}
134	            >
135	              Edit
136	            </button>
137	          </div>
138	        )}
139	
140	        {/* 3. Assignee field (editable) */}
141	        {isEditingAssignee ? (
142	          <div className="modal-field-edit">
143	            <input
144	              ref={assigneeInputRef}
145	              aria-label="Assignee"
146	              value={editAssignee}
147	              onChange={e => setEditAssignee(e.target.value)}
148	              onKeyDown={e => { if (e.key === 'Enter') handleSaveAssignee() }}
149	            />
150	            <button aria-label="Save" onClick={handleSaveAssignee} disabled={isSaving}>
151	              {isSaving ? 'Saving…' : 'Save'}
152	            </button>
153	            <button
154	              aria-label="Cancel"
155	              disabled={isSaving}
156	              onClick={() => { setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null) }}
157	            >
158	              Cancel
159	            </button>
160	          </div>
161	        ) : (
162	          <div className="modal-field-view">
163	            <p className="modal-assignee">
164	              <strong>Assignee:</strong> {card.assignee ?? 'Unassigned'}
165	            </p>
166	            <button
167	              aria-label="Edit assignee"
168	              onClick={() => {
169	                setIsEditingAssignee(true); setEditAssignee(card.assignee ?? '')
170	                // Mutual exclusivity: close title edit if open
171	                setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
172	              }}
173	            >
174	              Edit
175	            </button>
176	          </div>
177	        )}
178	
179	        {/* 4. Description (read-only) */}
180	        <p className="modal-description">{card.description ?? 'No description'}</p>
181	
182	        {/* 5. Error alert */}
183	        {saveError && <p role="alert" className="modal-error">{saveError}</p>}
184	
185	        {/* 6. Comments section */}
186	        <section className="modal-comments">
187	          <h3 className="modal-comments-heading">Comments</h3>
188	          {card.comments.length === 0 ? (
189	            <p className="modal-no-comments">No comments yet</p>
190	          ) : (
191	            <ul className="modal-comments-list">
192	              {card.comments.map(cm => (
193	                <li key={cm.id} data-testid="comment" className="modal-comment">
194	                  <div className="modal-comment-meta">
195	                    <span className="modal-comment-author">{cm.author}</span>
196	                    <time
197	                      className="modal-comment-time"
198	                      dateTime={new Date(cm.created_at).toISOString()}
199	                    >
200	                      {new Date(cm.created_at).toLocaleString()}
201	                    </time>
202	                  </div>
203	                  <p className="modal-comment-content">{cm.content}</p>
204	                </li>
205	              ))}
206	            </ul>
207	          )}
208	        </section>
209	
210	        {/* 7. Delete button / confirmation */}
211	        {showDeleteConfirm ? (
212	          <div className="modal-delete-confirm" role="region" aria-label="Delete confirmation">
213	            <p>Are you sure you want to delete this card?</p>
214	            <button
215	              aria-label="Confirm delete"
216	              onClick={handleConfirmDelete}
217	              disabled={isDeleting}
218	            >
219	              {isDeleting ? 'Deleting…' : 'Confirm delete'}
220	            </button>
221	            <button
222	              aria-label="Keep card"
223	              onClick={() => setShowDeleteConfirm(false)}
224	              disabled={isDeleting}
225	            >
226	              Keep card
227	            </button>
228	          </div>
229	        ) : (
230	          <button
231	            className="modal-delete"
232	            aria-label="Delete"
233	            onClick={() => setShowDeleteConfirm(true)}
234	          >
235	            Delete
236	          </button>
237	        )}
238	      </div>
239	    </div>,
240	    document.body
241	  )
242	}
