import CardTile from './CardTile.jsx'
import './Column.css'

export default function Column({ title, cards, onCardClick }) {
  return (
    <section className="column" aria-label={title}>
      <header className="column-header">
        <h2 className="column-title">{title}</h2>
        <span className="column-count" aria-label={`${cards.length} cards`}>
          {cards.length}
        </span>
      </header>
      <div className="column-cards">
        {cards.length === 0 ? (
          <p className="column-empty">No cards</p>
        ) : (
          cards.map(card => (
            <CardTile key={card.id} card={card} onCardClick={onCardClick} />
          ))
        )}
      </div>
    </section>
  )
}

import { render, screen, fireEvent } from '@testing-library/react'
import { describe, it, expect, vi } from 'vitest'
import Column from './Column.jsx'

const makeCard = (id, title, pos) => ({
  id,
  title,
  assignee: 'Alice',
  description: 'desc',
  column: 'ready',
  position: pos,
  created_at: Date.now(),
  comments: [],
})

const MOCK_CARDS = [
  makeCard('1', 'Card One', 1),
  makeCard('2', 'Card Two', 2),
  makeCard('3', 'Card Three', 3),
]

describe('Column', () => {
  it('renders the column title', () => {
    render(<Column title="Ready" cards={MOCK_CARDS} onCardClick={vi.fn()} />)
    expect(screen.getByRole('heading', { name: 'Ready' })).toBeInTheDocument()
  })

  it('renders card count equal to number of cards', () => {
    render(<Column title="Ready" cards={MOCK_CARDS} onCardClick={vi.fn()} />)
    expect(screen.getByLabelText('3 cards')).toBeInTheDocument()
  })

  it('renders 0 count for empty column', () => {
    render(<Column title="Ready" cards={[]} onCardClick={vi.fn()} />)
    expect(screen.getByLabelText('0 cards')).toBeInTheDocument()
  })

  it('renders a CardTile for each card', () => {
    render(<Column title="Ready" cards={MOCK_CARDS} onCardClick={vi.fn()} />)
    expect(screen.getByText('Card One')).toBeInTheDocument()
    expect(screen.getByText('Card Two')).toBeInTheDocument()
    expect(screen.getByText('Card Three')).toBeInTheDocument()
  })

  it('renders empty state message when no cards', () => {
    render(<Column title="Ready" cards={[]} onCardClick={vi.fn()} />)
    expect(screen.getByText(/no cards/i)).toBeInTheDocument()
  })

  it('calls onCardClick with the correct card when a CardTile is clicked', () => {
    const handler = vi.fn()
    render(<Column title="Ready" cards={MOCK_CARDS} onCardClick={handler} />)
    fireEvent.click(screen.getByRole('button', { name: 'Card One' }))
    expect(handler).toHaveBeenCalledWith(MOCK_CARDS[0])
  })
})

import { useState } from 'react'
import { useBoard } from '../../hooks/useBoard.js'
import Column from './Column.jsx'
import CardModal from './CardModal.jsx'
import './Board.css'

export default function Board() {
  const { cards, loading, error, updateCard, deleteCard } = useBoard()
  const [selectedCardId, setSelectedCardId] = useState(null)
  const allCards = [...cards.ready, ...cards.in_progress, ...cards.done]
  const selectedCard = selectedCardId ? (allCards.find(c => c.id === selectedCardId) ?? null) : null

  if (loading) return <div className="board-loading" aria-label="Loading">Loading…</div>
  if (error) return <div className="board-error" role="alert">{error}</div>

  return (
    <div className="board">
      <Column title="Ready" cards={cards.ready} onCardClick={(card) => setSelectedCardId(card.id)} />
      <Column title="In Progress" cards={cards.in_progress} onCardClick={(card) => setSelectedCardId(card.id)} />
      <Column title="Done" cards={cards.done} onCardClick={(card) => setSelectedCardId(card.id)} />
      {selectedCard && (
        <CardModal
          card={selectedCard}
          onClose={() => setSelectedCardId(null)}
          onUpdate={updateCard}
          onDelete={deleteCard}
        />
      )}
    </div>
  )
}

