226	              Keep card
227	            </button>
228	          </div>
229	        ) : (
230	          <button
231	            className="modal-delete"
232	            aria-label="Delete"
233	            onClick={() => setShowDeleteConfirm(true)}
234	          >
235	            Delete
236	          </button>
237	        )}
238	      </div>
239	    </div>,
240	    document.body
241	  )
242	}
